type bookingEntryJoins[Q dialect.Joinable] struct {
	typ      string
	Driver   modAs[Q, driverColumns]
	Event    modAs[Q, eventColumns]
	RaceGrid modAs[Q, raceGridColumns]
	Race     modAs[Q, raceColumns]
	Team     modAs[Q, teamColumns]
}

func (j bookingEntryJoins[Q]) aliasedAs(alias string) bookingEntryJoins[Q] {
	return buildBookingEntryJoins[Q](buildBookingEntryColumns(alias), j.typ)
}

func buildBookingEntryJoins[Q dialect.Joinable](cols bookingEntryColumns, typ string) bookingEntryJoins[Q] {
	return bookingEntryJoins[Q]{
		typ: typ,
		Driver: modAs[Q, driverColumns]{
			c: Drivers.Columns,
			f: func(to driverColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Drivers.Name().As(to.Alias())).On(
						to.ID.EQ(cols.DriverID),
					))
				}

				return mods
			},
		},
		Event: modAs[Q, eventColumns]{
			c: Events.Columns,
			f: func(to eventColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Events.Name().As(to.Alias())).On(
						to.ID.EQ(cols.EventID),
					))
				}

				return mods
			},
		},
		RaceGrid: modAs[Q, raceGridColumns]{
			c: RaceGrids.Columns,
			f: func(to raceGridColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, RaceGrids.Name().As(to.Alias())).On(
						to.ID.EQ(cols.RaceGridID),
					))
				}

				return mods
			},
		},
		Race: modAs[Q, raceColumns]{
			c: Races.Columns,
			f: func(to raceColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Races.Name().As(to.Alias())).On(
						to.ID.EQ(cols.RaceID),
					))
				}

				return mods
			},
		},
		Team: modAs[Q, teamColumns]{
			c: Teams.Columns,
			f: func(to teamColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Teams.Name().As(to.Alias())).On(
						to.ID.EQ(cols.TeamID),
					))
				}

				return mods
			},
		},
	}
}
